// Proceso de Serialización/Deserialización

// REQUEST (Cliente → Servidor)
// 1. Cliente envía JSON
{
  "name": "Pedro López",
  "phoneNumber": "+52-555-0000",
  "email": "pedro@email.com"
}

// 2. HttpMessageConverter (Jackson) deserializa JSON → CustomerRequest
CustomerRequest request = objectMapper.readValue(json, CustomerRequest.class);
// Usa setters o constructor para crear objeto

// 3. Controller recibe objeto Java
@PostMapping
public ResponseEntity<CustomerResponse> create(@RequestBody CustomerRequest request) {
    // request ya es objeto Java
}

// RESPONSE (Servidor → Cliente)
// 1. Service retorna objeto Java
CustomerResponse response = new CustomerResponse();
response.setId(1L);
response.setName("Pedro López");
response.setEmail("pedro@email.com");

// 2. HttpMessageConverter (Jackson) serializa objeto → JSON
String json = objectMapper.writeValueAsString(response);
// Usa getters para obtener valores

// 3. Cliente recibe JSON
{
  "id": 1,
  "name": "Pedro López",
  "email": "pedro@email.com",
  "phoneNumber": "+52-555-0000"
}

// Anotaciones Jackson para personalización

@Data
public class CustomerResponse {

    private Long id;

    @JsonProperty("full_name")  // JSON usa "full_name" en vez de "name"
    private String name;

    @JsonIgnore  // Este campo NO aparece en JSON
    private String internalCode;

    @JsonFormat(pattern = "yyyy-MM-dd HH:mm:ss")
    private LocalDateTime createdAt;

    @JsonInclude(JsonInclude.Include.NON_NULL)  // Solo si no es null
    private String optionalField;
}

// Configuración global de ObjectMapper
@Configuration
public class JacksonConfig {

    @Bean
    public ObjectMapper objectMapper() {
        ObjectMapper mapper = new ObjectMapper();

        // Excluir campos null
        mapper.setSerializationInclusion(JsonInclude.Include.NON_NULL);

        // Formato de fechas
        mapper.registerModule(new JavaTimeModule());
        mapper.disable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);

        // Ignorar propiedades desconocidas en deserialización
        mapper.disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES);

        return mapper;
    }
}
